const fmt = (n) => '$' + Math.round(n).toLocaleString();
const fmtDate = (iso) => new Date(iso).toLocaleDateString('en-US', { month: 'short', day: 'numeric', hour: 'numeric', minute: '2-digit' });
const fmtMonth = (iso) => new Date(iso).toLocaleDateString('en-US', { month: 'long', year: 'numeric' });

const AGENCY_OWNER_ROLES = [
  'Agency Owner- Blueprint',
  'Agency Owner- The Foundation',
  'Agency Owner- The Key',
  'Agency Owner- AA FINANCIAL',
  'Agency Owner- Formula Financial',
  'Agency Owner- Stark Financial',
];

function getRoleColorClass(role) {
  if (!role) return 'owner';
  if (role.includes('Foundation') || role.includes('Stark')) return 'owner-foundation';
  if (role.includes('Key')) return 'owner-key';
  if (role.includes('Formula')) return 'owner-formula';
  if (role.includes('AA FINANCIAL')) return 'owner-aa';
  if (role.includes('Blueprint')) return 'owner-blueprint';
  return 'owner';
}

function getBadgeClass(role) {
  if (!role) return 'badge-gold';
  if (role.includes('Foundation') || role.includes('Stark')) return 'badge-silver';
  if (role.includes('Key') || role.includes('Blueprint')) return 'badge-gold';
  if (role.includes('Formula') || role.includes('AA FINANCIAL')) return 'badge-red';
  return 'badge-gold';
}

function getEasternMidnight() {
  // Get current time in Eastern (UTC-4 EDT / UTC-5 EST)
  const now = new Date();
  const eastern = new Date(now.toLocaleString('en-US', { timeZone: 'America/New_York' }));
  eastern.setHours(0, 0, 0, 0);
  // Convert back to UTC offset
  const offset = now - new Date(now.toLocaleString('en-US', { timeZone: 'America/New_York' }));
  return new Date(eastern.getTime() + offset);
}

function getEasternSunday() {
  const now = new Date();
  const eastern = new Date(now.toLocaleString('en-US', { timeZone: 'America/New_York' }));
  eastern.setDate(eastern.getDate() - eastern.getDay());
  eastern.setHours(0, 0, 0, 0);
  const offset = now - new Date(now.toLocaleString('en-US', { timeZone: 'America/New_York' }));
  return new Date(eastern.getTime() + offset);
}

function filterByPeriod(deals, period, customStart, customEnd) {
  const now = new Date();
  const easternNow = new Date(now.toLocaleString('en-US', { timeZone: 'America/New_York' }));
  return deals.filter(d => {
    const dt = new Date(d.posted_at);
    if (period === 'today') { return dt >= getEasternMidnight(); }
    if (period === 'week') { return dt >= getEasternSunday(); }
    if (period === 'month') {
      const e = new Date(now.toLocaleString('en-US', { timeZone: 'America/New_York' }));
      return new Date(d.posted_at).toLocaleString('en-US', { timeZone: 'America/New_York', month: 'numeric', year: 'numeric' }) ===
        e.toLocaleString('en-US', { month: 'numeric', year: 'numeric' });
    }
    if (period === 'year') {
      const e = new Date(now.toLocaleString('en-US', { timeZone: 'America/New_York' }));
      return new Date(d.posted_at).toLocaleString('en-US', { timeZone: 'America/New_York', year: 'numeric' }) === e.getFullYear().toString();
    }
    if (period === 'custom' && customStart && customEnd) {
      const s = new Date(customStart); s.setHours(0,0,0,0);
      const e = new Date(customEnd); e.setHours(23,59,59,999);
      return dt >= s && dt <= e;
    }
    return true;
  });
}

function groupDealsByMonth(deals) {
  const groups = {};
  deals.forEach(d => {
    const key = fmtMonth(d.posted_at);
    if (!groups[key]) groups[key] = [];
    groups[key].push(d);
  });
  return groups;
}

